import{_ as s,g as t,h as n,S as o}from"./chunks/vitepress-theme-teek.CE3NX6fu.js";const h=JSON.parse('{"title":"关于我","description":"摘要总结：从 Tech Stack 到 Insight Stack，当 AI 接管了实现，我更关注架构的权衡与产品的价值，专注：工程化 Spec 与 AI 编程磨合的实践 | Agent 落地 | 独立产品。","frontmatter":{"date":"2025-08-29T09:40:53.000Z","title":"关于我","description":"摘要总结：从 Tech Stack 到 Insight Stack，当 AI 接管了实现，我更关注架构的权衡与产品的价值，专注：工程化 Spec 与 AI 编程磨合的实践 | Agent 落地 | 独立产品。","coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/about_me_chinese.png","permalink":"/about/me","categories":["关于"]},"headers":[],"relativePath":"40.关于/01.关于我.md","filePath":"40.关于/01.关于我.md"}'),m={name:"40.关于/01.关于我.md"};function i(r,a,e,l,p,c){return n(),t("div",null,[...a[0]||(a[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /40.关于/01.关于我.md for this page in Markdown format</div><h1 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to “关于我”">​</a></h1><h2 id="我是谁" tabindex="-1">我是谁 <a class="header-anchor" href="#我是谁" aria-label="Permalink to “我是谁”">​</a></h2><p>我是一名拥有全栈背景的开发者, 技术底色源于工作几年后积累了较为扎实的工程化实践——从基础的 Web 前端到复杂的跨平台小程序基础框架的架构升级，再到基于 NodeJS 的服务端开发，这些经历锻炼了我对<strong>系统复杂度</strong>的掌控力、<strong>工程化能力</strong>以及<strong>项目推动与团队合作的能力</strong>。</p><p>自 2023 年 LLM 浪潮涌现以来，我深度投身于 AI 相关的技术探索。在工作与业余项目中，主导或参与了多个基于大模型的应用落地，积累了从 Prompt 调优到 Agentic Workflow 编排的一线经验，也多次参加了国内 AI 社区相关的技术分享与交流活动，了解了 AI 领域最新的技术趋势与实践。</p><blockquote><p><strong>Insight Stack = Engineering Logic × Product Sense × AI Force</strong></p></blockquote><p>目前，我主要在<strong>折腾</strong>和<strong>实践</strong>以下几个方向：</p><ul><li><strong>工程化 Spec 与 AI 编程磨合的实践</strong>：摸索 Vibe Coding 在复杂业务中的边界，针对 AI 生成代码&quot;易腐烂、臃肿&quot;且&quot;调试难度倒挂&quot;的痛点，尝试<strong>将SDD (规范驱动开发)范式注入到生成流</strong>。利用 OpenSpec 等工具确立工程约束，来解决生成代码的可维护性难题，从而跨越&quot;从 Demo 到生产级系统&quot;的鸿沟。</li><li><strong>Agentic Workflow 实践</strong>：不追求复杂的理论，而是在实际场景中测试智能体工作流的边界，看看如何把 AI 真正融入到代码编写、内容创作等流程中去。</li><li><strong>创意落地与小产品开发：</strong>以全栈技术为手段，尝试将自己的想法转化为<strong>&quot;小而美&quot;的独立作品</strong>，在实践中打磨产品思维（Product Sense）。</li></ul><h2 id="我的认知迭代" tabindex="-1">我的认知迭代 <a class="header-anchor" href="#我的认知迭代" aria-label="Permalink to “我的认知迭代”">​</a></h2><p>在很长一段时间里，我和大多数开发者一样，认为&quot;全栈&quot;就是收集更多的技术徽章：从 React 到 NestJS，从 Python 到 Rust。我曾以为技术的广度、扎实的工程化能力就是护城河。</p><p>但在 AI 重构代码生产方式与编程范式的今天，我意识到规则变了。现在的我，不再执着于手里有多少把锤子，而更关注能构建出怎样的建筑，也更愿意将自己定义为一个 <strong>&quot;Product Engineer&quot; (产品型工程师)</strong> 和 <strong>&quot;AI-Augmented Builder&quot; (AI 增强型构建者)</strong>。</p><p>在这个博客 <strong>Insight Stack</strong> 中，记录了我对技术角色的重新思考，我相信未来的全栈不再是线性的技能堆叠，而是一个新的全栈价值公式：</p><p><span class="katex-display"><span class="katex"><span class="katex-mathml"><math><semantics><mrow><mrow><mi mathvariant="bold">F</mi><mi mathvariant="bold">u</mi><mi mathvariant="bold">l</mi><mi mathvariant="bold">l</mi><mtext> </mtext><mi mathvariant="bold">S</mi><mi mathvariant="bold">t</mi><mi mathvariant="bold">a</mi><mi mathvariant="bold">c</mi><mi mathvariant="bold">k</mi></mrow><mspace width="0.277778em"></mspace><mo>=</mo><mspace width="0.277778em"></mspace><mo>(</mo><mrow><mi mathvariant="bold">E</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">g</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">g</mi></mrow><mspace width="0.277778em"></mspace><mo>+</mo><mspace width="0.277778em"></mspace><mrow><mi mathvariant="bold">P</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">d</mi><mi mathvariant="bold">u</mi><mi mathvariant="bold">c</mi><mi mathvariant="bold">t</mi></mrow><mo>)</mo><mspace width="0.277778em"></mspace><mo>×</mo><mspace width="0.277778em"></mspace><mrow><mi mathvariant="bold">A</mi><mi mathvariant="bold">I</mi></mrow></mrow><annotation encoding="application/x-tex">\\mathbf{Full\\ Stack} \\; = \\; (\\mathbf{Engineering} \\; + \\; \\mathbf{Product}) \\; \\times \\; \\mathbf{AI} </annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.75em;"></span><span class="strut bottom" style="height:1em;vertical-align:-0.25em;"></span><span class="base displaystyle textstyle uncramped"><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">F</span><span class="mord mathbf">u</span><span class="mord mathbf">l</span><span class="mord mathbf">l</span><span class="mord mspace"> </span><span class="mord mathbf">S</span><span class="mord mathbf">t</span><span class="mord mathbf">a</span><span class="mord mathbf">c</span><span class="mord mathbf">k</span></span><span class="mord mspace thickspace"></span><span class="mrel">=</span><span class="mord mspace thickspace"></span><span class="mopen">(</span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">E</span><span class="mord mathbf">n</span><span class="mord mathbf" style="margin-right:0.01597em;">g</span><span class="mord mathbf">i</span><span class="mord mathbf">n</span><span class="mord mathbf">e</span><span class="mord mathbf">e</span><span class="mord mathbf">r</span><span class="mord mathbf">i</span><span class="mord mathbf">n</span><span class="mord mathbf" style="margin-right:0.01597em;">g</span></span><span class="mord mspace thickspace"></span><span class="mbin">+</span><span class="mord mspace thickspace"></span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">P</span><span class="mord mathbf">r</span><span class="mord mathbf">o</span><span class="mord mathbf">d</span><span class="mord mathbf">u</span><span class="mord mathbf">c</span><span class="mord mathbf">t</span></span><span class="mclose">)</span><span class="mord mspace thickspace"></span><span class="mbin">×</span><span class="mord mspace thickspace"></span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">A</span><span class="mord mathbf">I</span></span></span></span></span></span></p><ul><li><strong>Engineering (工程力)——坚实的基石</strong>：工程力从&quot;代码设计与实现 (How)&quot;迁移至 <strong>&quot;架构交付 (What &amp; Why)&quot;</strong>。当 AI 接管了样板代码，工程师的价值体现为<strong>架构决策的权衡、复杂逻辑的审计与验收</strong>，以及构建从 Localhost 到 Production 的<strong>自动化交付体系</strong>。</li><li><strong>Product (产品力)——价值的指引</strong>：产品力作为工程力的方向盘，具备 &quot;同理心&quot; 与 &quot;MVP 思维&quot;。这意味着跳出技术自嗨，精准捕捉用户的真实痛点，计算体验 ROI，敏锐地识别并实现那些 &quot;低成本高价值&quot; 的关键特性，拒绝盲目的过度设计。</li><li><strong>AI (AI 杠杆)——指数级倍增器</strong>：AI 不仅仅是工具，更是让个人能力产生爆炸式增长的 乘数。它通过 Context Engineering 抹平了前后端的技术门槛（技能补全），并将从 Idea 到 Demo 的周期从数周压缩至数小时（时间压缩），让 &quot;超级个体&quot; 成为可能。</li></ul><p>如果你对这些思考感兴趣，推荐阅读我的两篇核心文章：</p><ul><li><a href="/fullstack">不止于代码：构建 AI 时代全栈工程师的&quot;认知三层塔&quot;</a></li><li><a href="/product-sense">当&quot;实现&quot;不再是壁垒：工程师如何构建 Product Sense 这一核心护城河？</a></li></ul><h2 id="连接与交流" tabindex="-1">连接与交流 <a class="header-anchor" href="#连接与交流" aria-label="Permalink to “连接与交流”">​</a></h2><p>最好的学习是公开分享，最快的成长是与优秀者同行。无论是探讨<strong>全栈</strong>、<strong>AI 编程与应用</strong>、<strong>Agent 落地</strong>，还是交流<strong>产品心得</strong>，都非常欢迎你联系我~</p><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p><strong>联系方式</strong></p><ul><li>💬 <strong>微信</strong>：<code>hfutsqliang</code> (请备注：Insight Stack 和你的姓名)</li><li>📮 <strong>邮箱</strong>： <ul><li><code>hfutsqliang@qq.com</code></li><li><code>hfutsqliang@gmail.com</code></li></ul></li><li>🔗 <strong>Github：</strong><a href="https://github.com/sqliang" target="_blank" rel="noreferrer">https://github.com/sqliang</a></li></ul></div>',19)])])}const g=s(m,[["render",i]]);export{h as __pageData,g as default};
